/**
 * Image test fixture generator.
 *
 * Creates minimal valid image files for testing the ImageMetadataExtractor.
 * Each image is a 1x1 pixel in the respective format, generated from raw bytes
 * or via sharp for formats that require complex encoding (TIFF, EXIF JPEG).
 *
 * The hand-crafted byte arrays have been validated manually (open correctly in
 * image viewers and pass format-specific magic byte checks). If a byte is wrong,
 * the fixture existence tests will still pass but format-aware parsers may reject them.
 *
 * @module tests/fixtures/documents/image-fixtures
 */

import * as fs from "node:fs/promises";
import * as path from "node:path";
import sharp from "sharp";

/**
 * Create a minimal 1x1 JPEG image.
 *
 * @returns JPEG file as a Buffer
 */
function createMinimalJpeg(): Buffer {
  // Minimal valid JPEG: SOI, APP0 (JFIF), DQT, SOF0, DHT, SOS, image data, EOI
  // This is a hand-crafted minimal JFIF JPEG encoding a single white pixel.
  return Buffer.from([
    // SOI (Start of Image)
    0xff, 0xd8,
    // APP0 (JFIF marker)
    0xff, 0xe0, 0x00, 0x10, 0x4a, 0x46, 0x49, 0x46, 0x00, 0x01, 0x01, 0x00, 0x00, 0x01, 0x00,
    0x01, 0x00, 0x00,
    // DQT (Define Quantization Table)
    0xff, 0xdb, 0x00, 0x43, 0x00, 0x08, 0x06, 0x06, 0x07, 0x06, 0x05, 0x08, 0x07, 0x07, 0x07,
    0x09, 0x09, 0x08, 0x0a, 0x0c, 0x14, 0x0d, 0x0c, 0x0b, 0x0b, 0x0c, 0x19, 0x12, 0x13, 0x0f,
    0x14, 0x1d, 0x1a, 0x1f, 0x1e, 0x1d, 0x1a, 0x1c, 0x1c, 0x20, 0x24, 0x2e, 0x27, 0x20, 0x22,
    0x2c, 0x23, 0x1c, 0x1c, 0x28, 0x37, 0x29, 0x2c, 0x30, 0x31, 0x34, 0x34, 0x34, 0x1f, 0x27,
    0x39, 0x3d, 0x38, 0x32, 0x3c, 0x2e, 0x33, 0x34, 0x32,
    // SOF0 (Start of Frame, baseline DCT)
    0xff, 0xc0, 0x00, 0x0b, 0x08, 0x00, 0x01, 0x00, 0x01, 0x01, 0x01, 0x11, 0x00,
    // DHT (Define Huffman Table - DC)
    0xff, 0xc4, 0x00, 0x1f, 0x00, 0x00, 0x01, 0x05, 0x01, 0x01, 0x01, 0x01, 0x01, 0x01, 0x00,
    0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08,
    0x09, 0x0a, 0x0b,
    // DHT (Define Huffman Table - AC)
    0xff, 0xc4, 0x00, 0xb5, 0x10, 0x00, 0x02, 0x01, 0x03, 0x03, 0x02, 0x04, 0x03, 0x05, 0x05,
    0x04, 0x04, 0x00, 0x00, 0x01, 0x7d, 0x01, 0x02, 0x03, 0x00, 0x04, 0x11, 0x05, 0x12, 0x21,
    0x31, 0x41, 0x06, 0x13, 0x51, 0x61, 0x07, 0x22, 0x71, 0x14, 0x32, 0x81, 0x91, 0xa1, 0x08,
    0x23, 0x42, 0xb1, 0xc1, 0x15, 0x52, 0xd1, 0xf0, 0x24, 0x33, 0x62, 0x72, 0x82, 0x09, 0x0a,
    0x16, 0x17, 0x18, 0x19, 0x1a, 0x25, 0x26, 0x27, 0x28, 0x29, 0x2a, 0x34, 0x35, 0x36, 0x37,
    0x38, 0x39, 0x3a, 0x43, 0x44, 0x45, 0x46, 0x47, 0x48, 0x49, 0x4a, 0x53, 0x54, 0x55, 0x56,
    0x57, 0x58, 0x59, 0x5a, 0x63, 0x64, 0x65, 0x66, 0x67, 0x68, 0x69, 0x6a, 0x73, 0x74, 0x75,
    0x76, 0x77, 0x78, 0x79, 0x7a, 0x83, 0x84, 0x85, 0x86, 0x87, 0x88, 0x89, 0x8a, 0x92, 0x93,
    0x94, 0x95, 0x96, 0x97, 0x98, 0x99, 0x9a, 0xa2, 0xa3, 0xa4, 0xa5, 0xa6, 0xa7, 0xa8, 0xa9,
    0xaa, 0xb2, 0xb3, 0xb4, 0xb5, 0xb6, 0xb7, 0xb8, 0xb9, 0xba, 0xc2, 0xc3, 0xc4, 0xc5, 0xc6,
    0xc7, 0xc8, 0xc9, 0xca, 0xd2, 0xd3, 0xd4, 0xd5, 0xd6, 0xd7, 0xd8, 0xd9, 0xda, 0xe1, 0xe2,
    0xe3, 0xe4, 0xe5, 0xe6, 0xe7, 0xe8, 0xe9, 0xea, 0xf1, 0xf2, 0xf3, 0xf4, 0xf5, 0xf6, 0xf7,
    0xf8, 0xf9, 0xfa,
    // SOS (Start of Scan)
    0xff, 0xda, 0x00, 0x08, 0x01, 0x01, 0x00, 0x00, 0x3f, 0x00, 0x7b, 0x40, 0x1b, 0x00,
    // EOI (End of Image)
    0xff, 0xd9,
  ]);
}

/**
 * Create a minimal 1x1 PNG image (white pixel).
 *
 * @returns PNG file as a Buffer
 */
function createMinimalPng(): Buffer {
  // PNG signature + IHDR + IDAT + IEND
  // This is a valid 1x1 white pixel PNG
  return Buffer.from([
    // PNG signature
    0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a,
    // IHDR chunk (width=1, height=1, bit depth=8, color type=2 RGB)
    0x00, 0x00, 0x00, 0x0d, 0x49, 0x48, 0x44, 0x52, 0x00, 0x00, 0x00, 0x01, 0x00, 0x00, 0x00,
    0x01, 0x08, 0x02, 0x00, 0x00, 0x00, 0x90, 0x77, 0x53, 0xde,
    // IDAT chunk (compressed pixel data: filter=none, white pixel)
    0x00, 0x00, 0x00, 0x0c, 0x49, 0x44, 0x41, 0x54, 0x08, 0xd7, 0x63, 0xf8, 0xcf, 0xc0, 0x00,
    0x00, 0x00, 0x03, 0x00, 0x01, 0x36, 0x28, 0x19, 0x00,
    // IEND chunk
    0x00, 0x00, 0x00, 0x00, 0x49, 0x45, 0x4e, 0x44, 0xae, 0x42, 0x60, 0x82,
  ]);
}

/**
 * Create a minimal 1x1 GIF image (white pixel).
 *
 * @returns GIF file as a Buffer
 */
function createMinimalGif(): Buffer {
  return Buffer.from([
    // Header: GIF89a
    0x47, 0x49, 0x46, 0x38, 0x39, 0x61,
    // Logical screen descriptor (1x1, no global color table implied by flags=0x00)
    0x01, 0x00, 0x01, 0x00, 0x00, 0x00, 0x00,
    // Image descriptor
    0x2c, 0x00, 0x00, 0x00, 0x00, 0x01, 0x00, 0x01, 0x00, 0x00,
    // Image data (LZW minimum code size=2, block of 2 bytes)
    0x02, 0x02, 0x4c, 0x01, 0x00,
    // Trailer
    0x3b,
  ]);
}

/**
 * Create a minimal 1x1 WebP image using sharp.
 *
 * Hand-crafted VP8 bitstreams are fragile across sharp versions,
 * so we use sharp to generate a valid WebP instead.
 *
 * @returns Promise resolving to WebP file as a Buffer
 */
async function createMinimalWebp(): Promise<Buffer> {
  return await sharp({
    create: {
      width: 1,
      height: 1,
      channels: 3,
      background: { r: 255, g: 255, b: 255 },
    },
  })
    .webp()
    .toBuffer();
}

/**
 * Create a minimal 1x1 TIFF image using sharp.
 *
 * @returns Promise resolving to TIFF file as a Buffer
 */
async function createMinimalTiff(): Promise<Buffer> {
  return await sharp({
    create: {
      width: 1,
      height: 1,
      channels: 3,
      background: { r: 255, g: 255, b: 255 },
    },
  })
    .tiff()
    .toBuffer();
}

/**
 * Create a JPEG image with EXIF metadata using sharp.
 *
 * Injects known EXIF tags (Make, Model, Orientation) for verifiable
 * extraction in tests.
 *
 * @returns Promise resolving to JPEG file with EXIF as a Buffer
 */
async function createJpegWithExif(): Promise<Buffer> {
  return await sharp({
    create: {
      width: 2,
      height: 2,
      channels: 3,
      background: { r: 128, g: 128, b: 128 },
    },
  })
    .withExif({
      IFD0: {
        Make: "TestCamera",
        Model: "ModelX",
        Orientation: "6",
      },
    })
    .jpeg()
    .toBuffer();
}

/**
 * Create a corrupt JPEG file (valid SOI marker followed by garbage data).
 *
 * @returns Buffer with corrupt JPEG data
 */
function createCorruptJpeg(): Buffer {
  // JPEG SOI marker followed by garbage data
  return Buffer.from([
    0xff, 0xd8, 0x00, 0x00, 0xde, 0xad, 0xbe, 0xef, 0x00, 0x00, 0x00, 0x00, 0xff, 0xd9,
  ]);
}

/**
 * Create a truncated JPEG file (valid header, cut short before image data completes).
 *
 * Takes the minimal valid JPEG and removes the EOI marker and trailing bytes,
 * simulating a download interrupted mid-stream.
 *
 * @returns Buffer with truncated JPEG data
 */
function createTruncatedJpeg(): Buffer {
  const full = createMinimalJpeg();
  // Remove the last 4 bytes (2 bytes of scan data + EOI marker 0xFF 0xD9) to simulate truncation
  return Buffer.from(full.buffer, full.byteOffset, full.length - 4);
}

/**
 * Create a truncated PNG file (valid header and IHDR, but missing IEND chunk).
 *
 * Takes the minimal valid PNG and removes the IEND chunk,
 * simulating an incomplete file transfer.
 *
 * @returns Buffer with truncated PNG data
 */
function createTruncatedPng(): Buffer {
  const full = createMinimalPng();
  // Remove the last 12 bytes (IEND chunk: 4 length + 4 type + 4 CRC)
  return Buffer.from(full.buffer, full.byteOffset, full.length - 12);
}

/**
 * Create test image files in the fixtures directory.
 *
 * Writes image files into an `images/` subdirectory under the given fixtures dir.
 */
export async function createTestImageFiles(fixturesDir: string): Promise<void> {
  const imagesDir = path.join(fixturesDir, "images");
  await fs.mkdir(imagesDir, { recursive: true });

  const [tiffBuffer, exifJpegBuffer, webpBuffer] = await Promise.all([
    createMinimalTiff(),
    createJpegWithExif(),
    createMinimalWebp(),
  ]);

  await Promise.all([
    fs.writeFile(path.join(imagesDir, "photo.jpg"), createMinimalJpeg()),
    fs.writeFile(path.join(imagesDir, "screenshot.png"), createMinimalPng()),
    fs.writeFile(path.join(imagesDir, "animated.gif"), createMinimalGif()),
    fs.writeFile(path.join(imagesDir, "diagram.webp"), webpBuffer),
    fs.writeFile(path.join(imagesDir, "test.tiff"), tiffBuffer),
    fs.writeFile(path.join(imagesDir, "photo-with-exif.jpg"), exifJpegBuffer),
    fs.writeFile(path.join(imagesDir, "corrupt.jpg"), createCorruptJpeg()),
    fs.writeFile(path.join(imagesDir, "truncated.jpg"), createTruncatedJpeg()),
    fs.writeFile(path.join(imagesDir, "truncated.png"), createTruncatedPng()),
  ]);
}
